/**
  ******************************************************************************
  * @file    stm32g0xx_it.c
  * @brief   Interrupt service routines.
  *
  * Provides interrupt handlers for the base project shell.
  * Stub weak implementations are provided for symbols that will be
  * replaced by future child modules (SCHED_IncTick, UART_IRQHandler).
  ******************************************************************************
  */

#include "main.h"
#include "stm32g0xx_it.h"

extern ADC_HandleTypeDef  hadc1;
extern TIM_HandleTypeDef  htim3;
extern TIM_HandleTypeDef  htim14;
extern DMA_HandleTypeDef  hdma_adc1;

extern UART_HandleTypeDef huart1;
extern UART_HandleTypeDef huart2;

/* ========================================================================== */
/*              Stub: Scheduler Tick Increment (weak, replaceable)            */
/* ========================================================================== */
/**
  * @brief  Stub for timer_scheduler module's SCHED_IncTick.
  *         Called from SysTick_Handler once per millisecond.
  *         Will be replaced when timer_scheduler.c is added.
  */
__attribute__((weak)) void SCHED_IncTick(void)
{
    /* No-op until timer_scheduler module is added. */
}

/* ========================================================================== */
/*              Stub: UART Interrupt Handler (weak, replaceable)              */
/* ========================================================================== */
/**
  * @brief  Stub for uart_driver module's UART_IRQHandler.
  *         Called from USART1/2 interrupt handlers.
  *         Will be replaced when uart_driver.c is added.
  * @param  id  UART peripheral identifier (1=USART1, 2=USART2).
  */
__attribute__((weak)) void UART_IRQHandler(uint32_t id)
{
    (void)id;
    /* Clear possible framing/idle/overrun flags to prevent lockup. */
    if (id == 1U) {
        (void)huart1.Instance->RDR;
        (void)huart1.Instance->ISR;
    } else if (id == 2U) {
        (void)huart2.Instance->RDR;
        (void)huart2.Instance->ISR;
    }
}

/* ========================================================================== */
/*                      Core Exception Handlers                               */
/* ========================================================================== */
void NMI_Handler(void)      { while (1) {} }
void HardFault_Handler(void){ while (1) {} }
void SVC_Handler(void)      { }
void PendSV_Handler(void)   { }

/* ========================================================================== */
/*                      System Tick Handler                                   */
/* ========================================================================== */
void SysTick_Handler(void)
{
    HAL_IncTick();
    SCHED_IncTick();
}

/* ========================================================================== */
/*                      DMA Interrupt Handlers                                */
/* ========================================================================== */
void DMA1_Ch1_IRQHandler(void)
{
    HAL_DMA_IRQHandler(&hdma_adc1);
}

/* ========================================================================== */
/*                      ADC Interrupt Handlers                                */
/* ========================================================================== */
void ADC1_IRQHandler(void)
{
    HAL_ADC_IRQHandler(&hadc1);
}

/* ========================================================================== */
/*                      Timer Interrupt Handlers                              */
/* ========================================================================== */
void TIM3_IRQHandler(void)
{
    HAL_TIM_IRQHandler(&htim3);
}

void TIM1_BRK_UP_TRG_COM_IRQHandler(void)
{
    HAL_TIM_IRQHandler(&htim3);
}

void TIM14_IRQHandler(void)
{
    HAL_TIM_IRQHandler(&htim14);
}

/* ========================================================================== */
/*                      UART Interrupt Handlers                               */
/* ========================================================================== */
void USART1_IRQHandler(void)
{
    UART_IRQHandler(1U);
}

void USART2_IRQHandler(void)
{
    UART_IRQHandler(2U);
}

