/**
  ******************************************************************************
  * @file    system_stm32g0xx.c
  * @author  (base project shell)
  * @brief   CMSIS Cortex-M0+ Device Peripheral Access Layer System Source File
  *
  * MCU: STM32G030F6P6 (TSSOP-20)
  * Project: Battery Internal Resistance Measurement System
  *
  * Provides:
  *   - SystemCoreClock variable (64 MHz for this project)
  *   - SystemInit()   �?Flash prefetch/buffer, VTOR, SystemCoreClockUpdate
  *   - SystemCoreClockUpdate() �?synchronize SystemCoreClock variable
  *   - AHBPrescTable / APBPrescTable �?used by HAL_RCC_GetSysClockFreq()
  *
  * Clock configuration: HSE 8MHz -> PLL -> 64MHz SysClk
  *   HSE = 8 MHz (external crystal)
  *   PLLM = /1, PLLN = x16, PLLR = /2
  *   SysClk = (8 MHz / 1 * 16) / 2 = 64 MHz
  *
  * Toolchain: Keil ArmClang V6.19 (MDK-ARM)
  ******************************************************************************
  */

/* Includes ------------------------------------------------------------------*/
#include "stm32g0xx.h"
#include <stdint.h>

/* ========================================================================== */
/*                        System Core Clock Variable                          */
/* ========================================================================== */
/** @brief Holds the current system core clock frequency in Hz. */
uint32_t SystemCoreClock = 64000000UL;   /* Default: 64 MHz */

/* ========================================================================== */
/*                         Prescaler Lookup Tables                            */
/* ========================================================================== */
/** @brief AHB prescaler lookup table (index = RCC_CFGR_HPRE[3:0] >> 4). */
const uint32_t AHBPrescTable[16] = {
    0U, 0U, 0U, 0U, 0U, 0U, 0U, 0U,     /* 0000-0111: /1 */
    1U, 2U, 3U, 4U, 6U, 7U, 8U, 9U      /* 1000-1111: /2,/4,/8,/16,/64,/128,/256,/512 */
};

/** @brief APB prescaler lookup table (index = RCC_CFGR_PPRE[2:0] >> 8). */
const uint32_t APBPrescTable[8] = {
    0U, 0U, 0U, 0U, 1U, 2U, 3U, 4U      /* 000-011: /1, 100: /2, 101: /4, 110: /8, 111: /16 */
};

/* ========================================================================== */
/*                          SystemInit Function                               */
/* ========================================================================== */
/**
  * @brief  Setup the microcontroller system.
  *
  * Initializes the Flash interface, the FPU (if present), and the system's
  * interrupt vector table offset. Called by the startup code before main().
  *
  * For STM32G030F6P6 (Cortex-M0+, no FPU):
  *   1. Enable Flash prefetch buffer for 64 MHz operation.
  *   2. Set VECT_TAB_OFFSET = 0 (vector table at FLASH_BASE).
  *   3. Update SystemCoreClock.
  *
  * @note   This function is called by the reset handler in startup file.
  */
void SystemInit(void)
{
    /* ---- Configure Flash for 64 MHz ---- */
    /*
     * FLASH_ACR: PRFTEN (prefetch enable) + SLEEP_PD (disable sleep power-down).
     * STM32G030 does NOT have data/instruction cache (only G0B1/G0C1 have them).
     * Only prefetch buffer is available on G030.
     */
    FLASH->ACR |= FLASH_ACR_PRFTEN;             /* Enable prefetch buffer */

    /*
     * Clear LATENCY bits and set to 2 wait states for 64 MHz (>48 MHz).
     * Note: FLASH_ACR_LATENCY is 2 bits on G0 (bit 0=LS, bit 1=HS).
     * FLASH_LATENCY_2 = 2U = 0x02.
     */
    FLASH->ACR = (FLASH->ACR & ~FLASH_ACR_LATENCY) | FLASH_ACR_LATENCY_2;

    /* ---- Set vector table offset ---- */
    SCB->VTOR = FLASH_BASE | 0x00;              /* Vector table at 0x08000000 */

    /* ---- Update SystemCoreClock ---- */
    SystemCoreClock = 64000000UL;
}

/* ========================================================================== */
/*                      SystemCoreClockUpdate Function                        */
/* ========================================================================== */
/**
  * @brief  Update SystemCoreClock variable based on current RCC configuration.
  *
  * This function reads the RCC clock source and dividers and updates
  * SystemCoreClock accordingly. In this project the clock is fixed at 64 MHz,
  * but this function provides the correct value for HAL_RCC_GetSysClockFreq().
  *
  * @note   This function can be called at any time to re-sync SystemCoreClock
  *         after a clock configuration change.

